sql:
SELECT COUNT(event_id) AS total_weather_events
FROM weather_events
WHERE state = 'California' AND event_type = 'Heavy Snow' AND year = 2021;

SELECT event_id, event_type, injuries_direct
FROM weather_events
ORDER BY injuries_direct DESC;

external_knowledge:
- 'Heavy snowflakes' metaphorically refers to 'Heavy Snow';
- 'Strong gusts' metaphorically refers to 'Strong Wind';
- 'Financial and agricultural wounds' metaphorically refer to 'damage_property' and 'damage_crops';
- 'Average hits on houses and fields' metaphorically refer to 'average_property_damage' and 'average_crops_damage' respectively.

